import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.BzQXgbNp.js";const l="/assets/dash-8.B8dj3TCb.png",u=JSON.parse('{"title":"📬 遠端郵局快遞與個人背包","description":"","frontmatter":{},"headers":[],"relativePath":"Web-Postal-Inventory.md","filePath":"Web-Postal-Inventory.md"}'),n={name:"Web-Postal-Inventory.md"};function i(s,e,d,c,h,_){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="📬-遠端郵局快遞與個人背包" tabindex="-1">📬 遠端郵局快遞與個人背包 <a class="header-anchor" href="#📬-遠端郵局快遞與個人背包" aria-label="Permalink to &quot;📬 遠端郵局快遞與個人背包&quot;">​</a></h1><p>本伺服器提供先進的跨維度離線快遞物流，讓玩家能在網頁上將金幣與物品發送給其他玩家。</p><p><img src="'+l+'" alt="網頁背包即時預覽與快遞發送"></p><hr><h2 id="🎒-1-個人遊戲背包實時預覽-36格" tabindex="-1">🎒 1. 個人遊戲背包實時預覽 (36格) <a class="header-anchor" href="#🎒-1-個人遊戲背包實時預覽-36格" aria-label="Permalink to &quot;🎒 1. 個人遊戲背包實時預覽 (36格)&quot;">​</a></h2><ul><li><strong>狀態限制</strong>：當您在遊戲內處於 <strong>線上</strong> 狀態時，此面板會透過 WebSocket 即時同步，在網頁端完整渲染您當前的 36 格背包畫面。</li><li><strong>發送快遞包裹</strong>： <ol><li>直接點選網頁背包中任何一格您想送出的物品。</li><li>在右側欄位中輸入 <strong>「收件人名稱」</strong> 與 <strong>「物品數量」</strong>。</li><li>點擊確認送出，該物品會立即從您遊戲內的背包中消失，並轉入物流系統，寄送給對方。</li></ol></li></ul><hr><h2 id="💸-2-金幣電子匯款" tabindex="-1">💸 2. 金幣電子匯款 <a class="header-anchor" href="#💸-2-金幣電子匯款" aria-label="Permalink to &quot;💸 2. 金幣電子匯款&quot;">​</a></h2><ul><li>支援線上與離線匯款。</li><li>在匯款面板中輸入對方的 Minecraft ID 以及金幣金額，即可直接從您的個人金幣帳戶扣除餘額，以快遞包裹形式發送給對方。</li></ul><hr><h2 id="📦-3-收件狀態追蹤" tabindex="-1">📦 3. 收件狀態追蹤 <a class="header-anchor" href="#📦-3-收件狀態追蹤" aria-label="Permalink to &quot;📦 3. 收件狀態追蹤&quot;">​</a></h2><p>所有發送與接收的快遞皆可在網頁端追蹤狀態：</p><ul><li><strong><code>已送達 (Delivered)</code></strong>：收件人已上線接收快遞物品。</li><li><strong><code>離線暫存 (Pending)</code></strong>：收件人目前離線，物品已安全儲存於伺服器雲端快遞庫中，待收件人下次登入遊戲時會自動收到彈出通知並派發。</li></ul>',13)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
